// FederationAdminServiceHandler is an implementation of the platform.v1.FederationAdminService
// service.
type FederationAdminServiceHandler interface {
	// CreateExternalIdP registers a new upstream IdP for the tenant.
	// For OIDC IdPs, oidc_client_secret is consumed and stored
	// bcrypt-hashed (TRD 06-05) and never returned. For SAML IdPs,
	// saml_metadata_xml MUST validate via platform/saml.XSWGuard +
	// ParseAndCacheMetadata (TRD 06-01) or the RPC returns
	// CodeInvalidArgument.
	CreateExternalIdP(context.Context, *connect.Request[v1.FederationAdminServiceCreateExternalIdPRequest]) (*connect.Response[v1.FederationAdminServiceCreateExternalIdPResponse], error)
	// GetExternalIdP fetches a single IdP by id within the tenant.
	// The response never includes oidc_client_secret material;
	// oidc_client_secret_set reports configured/not-configured state.
	GetExternalIdP(context.Context, *connect.Request[v1.FederationAdminServiceGetExternalIdPRequest]) (*connect.Response[v1.FederationAdminServiceGetExternalIdPResponse], error)
	// UpdateExternalIdP mutates IdP attributes. Setting
	// oidc_client_secret to a non-empty value replaces the stored secret;
	// empty means "leave unchanged". To clear an enabled IdP, set
	// enabled = false explicitly.
	UpdateExternalIdP(context.Context, *connect.Request[v1.FederationAdminServiceUpdateExternalIdPRequest]) (*connect.Response[v1.FederationAdminServiceUpdateExternalIdPResponse], error)
	// DeleteExternalIdP permanently removes an IdP configuration along
	// with the attached FederationPolicy. Federated accounts retain their
	// local records; subsequent federation attempts via the deleted IdP
	// are rejected.
	DeleteExternalIdP(context.Context, *connect.Request[v1.FederationAdminServiceDeleteExternalIdPRequest]) (*connect.Response[v1.FederationAdminServiceDeleteExternalIdPResponse], error)
	// ListExternalIdPs returns a paginated list of IdPs in the tenant.
	ListExternalIdPs(context.Context, *connect.Request[v1.FederationAdminServiceListExternalIdPsRequest]) (*connect.Response[v1.FederationAdminServiceListExternalIdPsResponse], error)
	// CreateAttributeMapping registers a new attribute mapping in the
	// tenant. Multiple ExternalIdPs may reference the same mapping.
	CreateAttributeMapping(context.Context, *connect.Request[v1.FederationAdminServiceCreateAttributeMappingRequest]) (*connect.Response[v1.FederationAdminServiceCreateAttributeMappingResponse], error)
	// UpdateAttributeMapping mutates the mapping. Existing IdPs referencing
	// this mapping pick up the change on their next federation attempt.
	UpdateAttributeMapping(context.Context, *connect.Request[v1.FederationAdminServiceUpdateAttributeMappingRequest]) (*connect.Response[v1.FederationAdminServiceUpdateAttributeMappingResponse], error)
	// DeleteAttributeMapping removes the mapping. The RPC returns
	// CodeFailedPrecondition if any ExternalIdP still references it.
	DeleteAttributeMapping(context.Context, *connect.Request[v1.FederationAdminServiceDeleteAttributeMappingRequest]) (*connect.Response[v1.FederationAdminServiceDeleteAttributeMappingResponse], error)
	// ListAttributeMappings returns a paginated list of mappings in the
	// tenant.
	ListAttributeMappings(context.Context, *connect.Request[v1.FederationAdminServiceListAttributeMappingsRequest]) (*connect.Response[v1.FederationAdminServiceListAttributeMappingsResponse], error)
	// UpsertFederationPolicy creates or replaces the federation policy for
	// a (tenant, IdP) pair. Primary key is the (tenant_id, idp_id) pair —
	// there is at most one policy per IdP per tenant.
	UpsertFederationPolicy(context.Context, *connect.Request[v1.FederationAdminServiceUpsertFederationPolicyRequest]) (*connect.Response[v1.FederationAdminServiceUpsertFederationPolicyResponse], error)
	// GetFederationPolicy fetches the policy for a (tenant, IdP) pair.
	GetFederationPolicy(context.Context, *connect.Request[v1.FederationAdminServiceGetFederationPolicyRequest]) (*connect.Response[v1.FederationAdminServiceGetFederationPolicyResponse], error)
	// DeleteFederationPolicy removes the policy. With no policy present,
	// federation attempts default to the safe denial path.
	DeleteFederationPolicy(context.Context, *connect.Request[v1.FederationAdminServiceDeleteFederationPolicyRequest]) (*connect.Response[v1.FederationAdminServiceDeleteFederationPolicyResponse], error)
	// RegisterDownstreamSP creates a new SAML SP registration that AOID
	// will issue assertions to.
	RegisterDownstreamSP(context.Context, *connect.Request[v1.FederationAdminServiceRegisterDownstreamSPRequest]) (*connect.Response[v1.FederationAdminServiceRegisterDownstreamSPResponse], error)
	// ListDownstreamSPs returns a paginated list of SPs in the tenant.
	ListDownstreamSPs(context.Context, *connect.Request[v1.FederationAdminServiceListDownstreamSPsRequest]) (*connect.Response[v1.FederationAdminServiceListDownstreamSPsResponse], error)
	// DeleteDownstreamSP removes an SP registration. In-flight assertions
	// already issued remain valid for their lifetime.
	DeleteDownstreamSP(context.Context, *connect.Request[v1.FederationAdminServiceDeleteDownstreamSPRequest]) (*connect.Response[v1.FederationAdminServiceDeleteDownstreamSPResponse], error)
	// RegisterDownstreamClient is a thin convenience wrapper around
	// OAuthAdminService.CreateClient (Obj 4). It applies federation-friendly
	// defaults (client_type=confidential, grant_types=
	// [authorization_code, refresh_token], token_endpoint_auth_method=
	// client_secret_basic, default scopes openid+profile+email) and
	// returns the canonical OAuthClient + one-time client_secret. Admin
	// UIs that need finer control should call OAuthAdminService.CreateClient
	// directly instead.
	RegisterDownstreamClient(context.Context, *connect.Request[v1.FederationAdminServiceRegisterDownstreamClientRequest]) (*connect.Response[v1.FederationAdminServiceRegisterDownstreamClientResponse], error)
	// AddClientIdPOption enables an (OAuth client, external IdP) pairing so the
	// IdP is offered in that client's /authorize IdP picker. Idempotent on the
	// (client_id, idp_id) pair. The response carries the resulting option with
	// enabled = true.
	AddClientIdPOption(context.Context, *connect.Request[v1.FederationAdminServiceAddClientIdPOptionRequest]) (*connect.Response[v1.FederationAdminServiceAddClientIdPOptionResponse], error)
	// RemoveClientIdPOption DISABLES (enabled = false — it does NOT delete the
	// row, preserving the admin audit trail) an (OAuth client, external IdP)
	// pairing. The response carries the option with enabled = false.
	RemoveClientIdPOption(context.Context, *connect.Request[v1.FederationAdminServiceRemoveClientIdPOptionRequest]) (*connect.Response[v1.FederationAdminServiceRemoveClientIdPOptionResponse], error)
}

